import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, X, Calendar, Tag, Landmark, Save, Trash2 } from 'lucide-react';
import '../styles/Proventos.css';

const Proventos = () => {
  const [lista, setLista] = useState([]);
  const [categorias, setCategorias] = useState([]); // Estado para as categorias do banco
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  const [form, setForm] = useState({ 
    descricao: '', 
    valor_exibicao: 'R$ 0,00', 
    categoria_id: '', // Usando ID agora
    data: new Date().toISOString().split('T')[0] 
  });

  useEffect(() => {
    buscarDadosIniciais();
  }, []);

  async function buscarDadosIniciais() {
    setLoading(true);
    try {
      // Busca os proventos
      const { data: provs } = await supabase
        .from('proventos')
        .select(`*, categorias (nome, cor)`) // Join com categorias
        .order('data_recebimento', { ascending: false });
      
      // Busca as categorias do tipo 'provento' ou 'receita' (ajuste conforme seu banco)
      const { data: cats } = await supabase
        .from('categorias')
        .select('*')
        .eq('tipo', 'provento'); // Filtro solicitado

      setLista(provs || []);
      setCategorias(cats || []);

      // Define a primeira categoria como padrão no form se existir
      if (cats && cats.length > 0) {
        setForm(prev => ({ ...prev, categoria_id: cats[0].id }));
      }
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setLoading(false);
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  const handleMascaraMoeda = (e) => {
    let valor = e.target.value.replace(/\D/g, "");
    const valorNumerico = (Number(valor) / 100).toFixed(2);
    const valorFormatado = new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(valorNumerico);
    setForm({ ...form, valor_exibicao: valorFormatado });
  };

  const abrirModalNovo = () => {
    setEditandoId(null);
    setForm({ 
      descricao: '', 
      valor_exibicao: 'R$ 0,00', 
      categoria_id: categorias[0]?.id || '', 
      data: new Date().toISOString().split('T')[0] 
    });
    setShowModal(true);
  };

  const abrirModalEditar = (item) => {
    setEditandoId(item.id);
    setForm({
      descricao: item.descricao,
      valor_exibicao: formatMoney(item.valor),
      categoria_id: item.categoria_id,
      data: item.data_recebimento
    });
    setShowModal(true);
  };

  async function handleSalvar(e) {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();
    const valorLimpo = Number(form.valor_exibicao.replace(/[^\d,]/g, '').replace(',', '.'));

    const dadosProvento = {
      user_id: user.id,
      descricao: form.descricao,
      valor: valorLimpo,
      categoria_id: form.categoria_id, // Salvando a FK
      data_recebimento: form.data
    };

    let error;
    if (editandoId) {
      const { error: err } = await supabase.from('proventos').update(dadosProvento).eq('id', editandoId);
      error = err;
    } else {
      const { error: err } = await supabase.from('proventos').insert([dadosProvento]);
      error = err;
    }

    if (!error) {
      setShowModal(false);
      buscarDadosIniciais();
    }
  }

  async function handleExcluir() {
    if (window.confirm("Deseja excluir esta entrada?")) {
      const { error } = await supabase.from('proventos').delete().eq('id', editandoId);
      if (!error) {
        setShowModal(false);
        buscarDadosIniciais();
      }
    }
  }

  return (
    <>
      <div className="proventos-premium-wrapper">
        <div className="prov-top-layout">
          <header className="prov-panel prov-header-area">
            <div className="prov-title-area">
              <h1>Proventos</h1>
              <p>Entradas e Rendas</p>
            </div>
          </header>
          <div className="prov-panel prov-summary-card">
            <span className="summary-label">Total Recebido</span>
            <h2 className="summary-value">
              {formatMoney(lista.reduce((acc, cur) => acc + parseFloat(cur.valor), 0))}
            </h2>
          </div>
        </div>

        <main className="prov-panel" style={{padding: 0, overflow: 'hidden'}}>
          <div style={{padding: '25px 30px', borderBottom: '1px solid #f1f5f9'}}>
            <h3 style={{margin: 0, fontWeight: 800, color: '#475569'}}>Histórico de Entradas</h3>
          </div>

          <div className="prov-list">
            {loading ? (
              <div style={{padding: '40px', textAlign: 'center'}}>Carregando...</div>
            ) : lista.map(item => (
              <div key={item.id} className="prov-item-row" onClick={() => abrirModalEditar(item)}>
                <div className="prov-left-content">
                  <div className="prov-icon-box" style={{color: item.categorias?.cor || '#10b981', background: `${item.categorias?.cor}15`}}>
                    <Landmark size={20} />
                  </div>
                  <div className="prov-details">
                    <span className="prov-desc">{item.descricao}</span>
                    <div className="prov-meta">
                      <span className="meta-tag"><Calendar size={12} /> {new Date(item.data_recebimento).toLocaleDateString()}</span>
                      <span className="meta-tag"><Tag size={12} /> {item.categorias?.nome || 'Sem Categoria'}</span>
                    </div>
                  </div>
                </div>
                <span className="prov-value">{formatMoney(item.valor)}</span>
              </div>
            ))}
          </div>
        </main>

        {showModal && (
          <div className="modal-overlay" onClick={() => setShowModal(false)}>
            <div className="prov-modal" onClick={e => e.stopPropagation()}>
              <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px'}}>
                <h2 style={{margin: 0, fontWeight: 900}}>{editandoId ? 'Editar Entrada' : 'Nova Receita'}</h2>
                <button onClick={() => setShowModal(false)} style={{background: '#f1f5f9', border: 'none', padding: '10px', borderRadius: '12px', cursor: 'pointer'}}>
                  <X size={20} color="#64748b" />
                </button>
              </div>
              
              <form onSubmit={handleSalvar}>
                <div className="form-group">
                  <label>Descrição</label>
                  <input type="text" required value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} placeholder="Ex: Salário Mensal" />
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label>Valor</label>
                    <input type="text" required value={form.valor_exibicao} onChange={handleMascaraMoeda} />
                  </div>
                  <div className="form-group">
                    <label>Data</label>
                    <input type="date" required value={form.data} onChange={e => setForm({...form, data: e.target.value})} />
                  </div>
                </div>

                <div className="form-group">
                  <label>Categoria</label>
                  <select 
                    value={form.categoria_id} 
                    onChange={e => setForm({...form, categoria_id: e.target.value})}
                    required
                  >
                    <option value="" disabled>Selecione uma categoria</option>
                    {categorias.map(cat => (
                      <option key={cat.id} value={cat.id}>{cat.nome}</option>
                    ))}
                  </select>
                </div>

                <button type="submit" className="btn-save-prov">
                  <Save size={18} /> {editandoId ? 'Salvar Alterações' : 'Confirmar Receita'}
                </button>

                {editandoId && (
                  <button type="button" onClick={handleExcluir} style={{width: '100%', marginTop: '10px', background: '#fef2f2', color: '#ef4444', border: 'none', padding: '12px', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px'}}>
                    <Trash2 size={18} /> Excluir Registro
                  </button>
                )}
              </form>
            </div>
          </div>
        )}
      </div>

      <button className="prov-fab" onClick={abrirModalNovo}>
        <Plus size={30} />
      </button>
    </>
  );
};

export default Proventos;
